export function binarySearchBoundary(values: number[], target: number): number {
    let left = 0;
    let right = values.length - 1;
    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        if (values[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    if (left < values.length && values[left] === target) {
        return left;
    }
    return -1;
}

