export function dijkstraShortestPath(nodeCount: number, edges: readonly (readonly [number, number, number])[], start: number, end: number): number | null {
    const adj: number[][][] = Array.from({ length: nodeCount }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
    }

    const dist: number[] = new Array(nodeCount).fill(Infinity);
    dist[start] = 0;

    // Min-heap implementation or use a simple array? 
    // For performance, a binary heap is better.
    // Let's implement a simple binary heap.

    const heap: [number, number][] = [[0, start]];

    // Helper functions for heap
    const swap = (i: number, j: number) => {
        const temp = heap[i];
        heap[i] = heap[j];
        heap[j] = temp;
    };

    const push = (item: [number, number]) => {
        heap.push(item);
        let i = heap.length - 1;
        while (i > 0) {
            const parent = (i - 1) >> 1;
            if (heap[parent][0] <= heap[i][0]) break;
            swap(parent, i);
            i = parent;
        }
    };

    const pop = (): [number, number] | undefined => {
        if (heap.length === 0) return undefined;
        const top = heap[0];
        const last = heap.pop()!;
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let smallest = i;
                const left = 2 * i + 1;
                const right = 2 * i + 2;
                if (left < heap.length && heap[left][0] < heap[smallest][0]) smallest = left;
                if (right < heap.length && heap[right][0] < heap[smallest][0]) smallest = right;
                if (smallest === i) break;
                swap(smallest, i);
                i = smallest;
            }
        }
        return top;
    };

    while (heap.length > 0) {
        const [d, u] = pop()!;
        if (d > dist[u]) continue;
        if (u === end) return d; // Optimization: can return early if we only need distance to end

        for (const [v, w] of adj[u]) {
            const newDist = d + w;
            if (newDist < dist[v]) {
                dist[v] = newDist;
                push([newDist, v]);
            }
        }
    }

    return dist[end] === Infinity ? null : dist[end];
}
