      const keys = [...currNode.children.keys()].sort();
      for (let i = keys.length - 1; i >= 0; i--) {
        stack.push([currNode.children.get(keys[i])!, currentStr + keys[i]]);
      }
    }

    results.push(completions);
  }

  return results;
}
