export function murmurhash3(str: string, seed: number): number {
    let h1 = seed >>> 0;
    const len = str.length;
    const totalBytes = len * 2;

    const c1 = 0xcc9e2d51;
    const c2 = 0x1b873593;

    let i = 0;
    for (; i + 1 < len; i += 2) {
        let k1 = str.charCodeAt(i) | (str.charCodeAt(i + 1) << 16);
        k1 = (k1 * c1) >>> 0;
        k1 = ((k1 << 15) | (k1 >>> 17)) >>> 0;
        k1 = (k1 * c2) >>> 0;
        h1 ^= k1;
        h1 = ((h1 << 13) | (h1 >>> 19)) >>> 0;
        h1 = ((h1 * 5) + 0xe6546b64) >>> 0;
    }

    if (i < len) {
        let k1 = str.charCodeAt(i);
        k1 = (k1 * c1) >>> 0;
        k1 = ((k1 << 15) | (k1 >>> 17)) >>> 0;
        k1 = (k1 * c2) >>> 0;
        h1 ^= k1;
    }

    h1 ^= totalBytes;
    h1 ^= h1 >>> 16;
    h1 = (h1 * 0x85ebca6b) >>> 0;
    h1 ^= h1 >>> 13;
    h1 = (h1 * 0xc2b2ae35) >>> 0;
    h1 ^= h1 >>> 16;

    return h1 >>> 0;
}

