export function evaluateBooleanExpression(expression: string): boolean {
    let pos = 0;
    const len = expression.length;

    function skipWhitespace() {
        while (pos < len && expression[pos] === ' ') pos++;
    }

    function peek(): string | undefined {
        skipWhitespace();
        if (pos >= len) return undefined;
        if (expression[pos] === '!' || expression[pos] === '(' || expression[pos] === ')') {
            return expression[pos];
        }
        if (expression[pos] === '&' && pos + 1 < len && expression[pos+1] === '&') {
            return '&&';
        }
        if (expression[pos] === '|' && pos + 1 < len && expression[pos+1] === '|') {
            return '||';
        }
        if (expression[pos] === 't') return 'true';
        if (expression[pos] === 'f') return 'false';
        return undefined;
    }

    function consume(token: string) {
        const p = peek();
        if (p !== token) throw new Error(`Expected ${token}`);
        pos += token.length;
    }

    function parseOr(): boolean {
        let left = parseAnd();
        while (peek() === '||') {
            consume('||');
            left = left || parseAnd();
        }
        return left;
    }

    function parseAnd(): boolean {
        let left = parseNot();
        while (peek() === '&&') {
            consume('&&');
            left = left && parseNot();
        }
        return left;
    }

    function parseNot(): boolean {
        if (peek() === '!') {
            consume('!');
            return !parseNot();
        }
        return parsePrimary();
    }

    function parsePrimary(): boolean {
        const token = peek();
        if (token === 'true') {
            consume('true');
            return true;
        }
        if (token === 'false') {
            consume('false');
            return false;
        }
        if (token === '(') {
            consume('(');
            const val = parseOr();
            consume(')');
            return val;
        }
        throw new Error(`Unexpected token: ${token}`);
    }

    const result = parseOr();
    if (pos < len) throw new Error('Unexpected characters');
    return result;
}

